dtsPropsFor.TandemLogo:
/** Pixel size of the square logo. Default 64. */
  size?: number;
  /** Animate the orbit expanding and spinning into place. Default true. */
  animate?: boolean;
  /** Extra class names applied to the root <svg>. */
  className?: string;

dtsPropsFor.EmptyState:
/** Heading shown inside the dashed placeholder frame. */
  title: string;
  /** Optional supporting line rendered under the title. */
  hint?: string;

dtsPropsFor.AgentToasts:
/** The live stack of agent-action popups (newest first). Each is an agent action stamped with an id + time. */
  toasts: { id: number; at: number; nonce: number; op: "created" | "updated" | "removed"; kind: string; mode: "welcome" | "map" | "itinerary" | "docs" | "roadmap" | "sheets" | "charts"; agentName: string; isClaude: boolean }[];
  /** Called with the toast id when a toast is dismissed (clicked). */
  onDismiss: (id: number) => void;

dtsPropsFor.AgentPresence:
/** Agents currently present in the canvas. Claude renders terracotta, other agents ink. */
  agents: { name: string; isClaude: boolean }[];
  /** The agent's live edit target, or null when it isn't editing. */
  edit: { entityId: string; mode: "welcome" | "map" | "itinerary" | "docs" | "roadmap" | "sheets" | "charts" } | null;
  /** Whether an agent is currently reading (scanning) the canvas. */
  reading: boolean;
  /** Jump to the mode an agent is editing. */
  onJump: (mode: "welcome" | "map" | "itinerary" | "docs" | "roadmap" | "sheets" | "charts") => void;
